from math import gcd
def max_points(points):
    if len(points) <= 2:
        return len(points)
    best = 0
    for i in range(len(points)):
        slopes = {}
        dup = 0
        x1, y1 = points[i]
        local = 0
        for j in range(i + 1, len(points)):
            x2, y2 = points[j]
            dx = x2 - x1
            dy = y2 - y1
            if dx == 0 and dy == 0:
                dup += 1
                continue
            g = gcd(dx, dy)
            dx //= g
            dy //= g
            if dx < 0:
                dx, dy = -dx, -dy
            if dx == 0:
                dy = 1
            if dy == 0:
                dx = 1
            key = (dy, dx)
            slopes[key] = slopes.get(key, 0) + 1
            if slopes[key] > local:
                local = slopes[key]
        best = max(best, local + dup + 1)
    return best

